import collections

def kosaraju(graph):
    all_nodes = set()
    for u in graph:
        all_nodes.add(u)
        for v in graph[u]:
            all_nodes.add(v)

    visited = set()
    order_stack = []

    def dfs1(node):
        visited.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                dfs1(neighbor)
        order_stack.append(node)

    for node in all_nodes:
        if node not in visited:
            dfs1(node)

    graph_t = collections.defaultdict(list)
    for u in graph:
        for v in graph[u]:
            graph_t[v].append(u)

    for node in all_nodes:
        if node not in graph_t:
            graph_t[node] = []

    visited = set()
    sccs = []

    def dfs2(node, current_scc):
        visited.add(node)
        current_scc.append(node)
        for neighbor in graph_t.get(node, []):
            if neighbor not in visited:
                dfs2(neighbor, current_scc)

    while order_stack:
        node = order_stack.pop()
        if node not in visited:
            current_scc = []
            dfs2(node, current_scc)
            sccs.append(current_scc)

    return sccs
